from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

# Initialize Redis client
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0)

# Allowed Redis commands for security
ALLOWED_COMMANDS = {'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'INCR', 'DECR'}

@app.route('/redis-command', methods=['GET'])
def execute_redis_command():
    command = request.args.get('command')
    if not command:
        return jsonify({'error': 'No command provided'}), 400

    command_parts = command.split()
    if not command_parts or command_parts[0].upper() not in ALLOWED_COMMANDS:
        return jsonify({'error': 'Command not allowed'}), 403

    try:
        result = redis_client.execute_command(*command_parts)
        return jsonify({'result': result}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)